import { AbsoluteFill, interpolate, spring, useCurrentFrame, useVideoConfig, Easing } from 'remotion';

const TITLE_FADE_IN_END = 30;

const CAPTIONS: { label: string; from: number; to: number }[] = [
  { label: 'one',   from: 120, to: 180 },
  { label: 'two',   from: 180, to: 240 },
  { label: 'three', from: 240, to: 300 },
];

export const MyVideo: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  // Title fade in over first 30 frames
  const titleOpacity = interpolate(frame, [0, TITLE_FADE_IN_END], [0, 1], {
    extrapolateLeft: 'clamp',
    extrapolateRight: 'clamp',
  });

  return (
    <AbsoluteFill style={{ backgroundColor: '#1a1a2e', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      {/* Title */}
      <div
        style={{
          position: 'absolute',
          top: '30%',
          width: '100%',
          textAlign: 'center',
          opacity: titleOpacity,
          color: '#ffffff',
          fontSize: 120,
          fontWeight: 700,
          fontFamily: 'sans-serif',
          letterSpacing: 8,
        }}
      >
        Hello
      </div>

      {/* Captions */}
      {CAPTIONS.map(({ label, from, to }) => {
        const isActive = frame >= from && frame < to;
        const localFrame = frame - from;

        const scale = isActive
          ? spring({
              frame: localFrame,
              fps,
              config: { damping: 12, stiffness: 200, mass: 0.5 },
              from: 0.6,
              to: 1,
            })
          : 0;

        const opacity = isActive
          ? interpolate(localFrame, [0, 8], [0, 1], {
              extrapolateLeft: 'clamp',
              extrapolateRight: 'clamp',
              easing: Easing.out(Easing.cubic),
            })
          : 0;

        return (
          <div
            key={label}
            style={{
              position: 'absolute',
              bottom: '25%',
              width: '100%',
              textAlign: 'center',
              color: '#f0c040',
              fontSize: 90,
              fontWeight: 800,
              fontFamily: 'sans-serif',
              opacity,
              transform: `scale(${scale})`,
            }}
          >
            {label}
          </div>
        );
      })}
    </AbsoluteFill>
  );
};
EOF

